/**
 * Cloudflare Worker — upload measurement sink
 *
 * Drains POST bodies via streaming without buffering.
 * Runs on Cloudflare's network (same infrastructure as our
 * download endpoint), so the measured upload speed reflects
 * the user's true last-mile → Cloudflare bandwidth.
 *
 * Deploy:  wrangler deploy          (from this directory)
 * URL:     https://ust-upload-proxy.<account>.workers.dev
 */
export default {
  async fetch(request) {
    // ── CORS preflight ───────────────────────────────────────────
    if (request.method === "OPTIONS") {
      return new Response(null, {
        status: 204,
        headers: {
          "Access-Control-Allow-Origin": "*",
          "Access-Control-Allow-Methods": "POST, OPTIONS",
          "Access-Control-Allow-Headers": "Content-Type",
          "Access-Control-Max-Age": "86400",
        },
      });
    }

    if (request.method !== "POST") {
      return new Response("Method Not Allowed", {
        status: 405,
        headers: { "Access-Control-Allow-Origin": "*" },
      });
    }

    // ── Stream-drain the body ────────────────────────────────────
    // reader.read() is I/O wait (not CPU), so it comfortably fits
    // within the 10 ms CPU-time budget of the free Workers tier.
    let bytes = 0;
    if (request.body) {
      const reader = request.body.getReader();
      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        bytes += value?.byteLength ?? 0;
      }
    }

    return new Response(String(bytes), {
      status: 200,
      headers: {
        "Access-Control-Allow-Origin": "*",
        "Cache-Control": "no-store",
        "Content-Type": "text/plain;charset=utf-8",
      },
    });
  },
};
